class Solution {
public:
    string shortestPalindrome(string s) {
        string rev = s;
        reverse(rev.begin(), rev.end());
        int i = 0;
        while (i < s.size() && rev[i] == s[s.size() - 1 - i]) i++;
        return rev.substr(0, rev.size() - i) + s;
    }
};
```

